CREATE TABLE client (
    id_client NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY, -- Clé primaire auto-générée
    nom_client VARCHAR2(255) NOT NULL,    -- Nom du client (obligatoire)
    adresse VARCHAR2(500),                -- Adresse du client
    pays VARCHAR2(100),                   -- Pays du client
    telephone VARCHAR2(20),               -- Numéro de téléphone
    vendeur VARCHAR2(255),                -- Nom du vendeur associé au client
    region VARCHAR2(255)                  -- Région du client
);

CREATE TABLE produit (
    id_produit NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY, -- Clé primaire auto-générée
    nom VARCHAR2(150) NOT NULL,      -- Nom du produit
    prix NUMBER(10, 2) NOT NULL,     -- Prix du produit avec deux décimales
    cout NUMBER(10, 2) NOT NULL,     -- Coût du produit avec deux décimales
    stock NUMBER DEFAULT 0,          -- Quantité en stock avec une valeur par défaut de 0
    date_cree DATE DEFAULT SYSDATE,  -- Date de création avec une valeur par défaut de la date actuelle
    categorie NUMBER                 -- Catégorie du produit (référence à une autre table, par exemple)
);

CREATE TABLE utilisateur (
    id_utilisateur NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY, -- Clé primaire auto-générée
    nom VARCHAR2(100) NOT NULL,        -- Nom de l'utilisateur
    prenom VARCHAR2(100) NOT NULL,     -- Prénom de l'utilisateur
    adresse VARCHAR2(255),             -- Adresse de l'utilisateur
    ville VARCHAR2(100),               -- Ville de l'utilisateur
    courriel VARCHAR2(255) NOT NULL UNIQUE, -- Courriel de l'utilisateur, doit être unique
    mdp VARCHAR2(255) NOT NULL         -- Mot de passe de l'utilisateur
);

CREATE TABLE panier (
    id_panier NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY, -- Clé primaire auto-générée
    id_client NUMBER NOT NULL,          -- Clé étrangère pour client
    date_creation DATE DEFAULT SYSDATE, -- Date de création avec valeur par défaut à la date actuelle
    id_utilisateur NUMBER NOT NULL,     -- Clé étrangère pour utilisateur
    note VARCHAR2(255),                 -- Note pour la panier
    CONSTRAINT fk_client FOREIGN KEY (id_client) REFERENCES client(id_client),
    CONSTRAINT fk_utilisateur FOREIGN KEY (id_utilisateur) REFERENCES utilisateur(id_utilisateur)
);

CREATE TABLE item (
    id_item NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY, -- Clé primaire auto-générée
    id_panier NUMBER NOT NULL,       -- Clé étrangère vers la table panier
    id_produit NUMBER NOT NULL,      -- Clé étrangère vers la table produit
    qte_commande NUMBER NOT NULL,    -- Quantité commandée
    prix NUMBER(10, 2) NOT NULL,     -- Prix du produit au moment de la commande
    escompte NUMBER(5, 2) DEFAULT 0, -- Escompte (pourcentage de réduction), valeur par défaut 0
    CONSTRAINT fk_panier FOREIGN KEY (id_panier) REFERENCES panier(id_panier),
    CONSTRAINT fk_produit FOREIGN KEY (id_produit) REFERENCES produit(id_produit)
);

